//React
import {React, Component, useState} from 'react';
import * as FaIcons from "react-icons/fa";


function PainelDeControle(props){ 
    const [campoDeOpcoes, setCampoDeOpcoes] = useState(null);
    const [contrExibicaoPainel, setContrExibicaoPainel] = useState(true);
    const [arrayDeOpcoes, setArrayDeOpcoes] = useState([{
        nomeCampo: "Eventos",
        formulario: <OpcoesEvento consultaEventos={props.consultaEventos} 
            gerarNovoEvento={props.gerarNovoEvento} capturarProximosEventos = {props.capturarProximosEventos} 
            fecharOpcoesEventos= {handleClickOpcao}/>,
        icone: <FaIcons.FaBirthdayCake size = {40} />,
        isClicked: false
   },
    {
        nomeCampo: "Clientes",
        formulario: <OpcoesCliente />,
        icone: <FaIcons.FaUserCircle size = {40}/>,
        isClicked: false
    },
    {
        nomeCampo: "Brinquedos",
        formulario: <OpcoesBrinquedo/>,
        icone: <FaIcons.FaSnowman size = {40}/>,
        isClicked: false
    }])

    //para abrir ou fechar um já aberto é só executar a função com o seguinte parâmetro
    //0 - eventos
    //1 - clientes
    //2 - brinquedos
    function handleClickOpcao(indexClicado){
        let arrayDeOpcoesProv = arrayDeOpcoes;
        arrayDeOpcoesProv.forEach((opcao, index) => {
            if((index === indexClicado && opcao.isClicked) || (indexClicado === null)){
                opcao.isClicked = false;
                setCampoDeOpcoes(null);
            }else if(index === indexClicado && !opcao.isClicked){
                opcao.isClicked = true;
                setCampoDeOpcoes(opcao.formulario);
            }else{
                opcao.isClicked = false;  
            }
        })
        setArrayDeOpcoes([...arrayDeOpcoesProv]);         
    }
        function handleClickFechar(){
            if(contrExibicaoPainel){
                setContrExibicaoPainel(false);
            }else{
                setContrExibicaoPainel(true);
            }
            handleClickOpcao(null);
        }
        
        return(
            <div id='PainelDeControle'>
                <div className='seletores'>
                    <div className='tituloPainel'>
                        <h4>Painel de Controle</h4>    
                    </div>
                    <div id='opcoes' className='configOpcoes'>
                        
                        <div>
                            <div>
                                <FaIcons.FaBirthdayCake size = {40} />
                            </div>
                            <div> 
                                <h5>
                                    Eventos
                                </h5>
                            </div>
                        </div>

                        <div>
                            <div>
                                <FaIcons.FaUserCircle size = {40}/>
                            </div>
                            <div> 
                                <h5>
                                    Clientes
                                </h5>
                            </div>
                        </div>

                        <div>
                            <div>
                                <FaIcons.FaSnowman size = {40}/>
                            </div>
                            <div> 
                                <h5>
                                    Brinquedos
                                </h5>
                            </div>
                        </div>
                           
                        
                    </div>
                </div>
                
                <div id='campoAberturaopcoes'>
                    {campoDeOpcoes? campoDeOpcoes : ''}
                </div>             
            </div>            
        )    
    
}

export default PainelDeControle;
